// ---- State ----
let stage='groups';
const order={};      // group -> [id,id,id,id]
let thirds=new Set(); // selected group letters (size 8)
const picks={};       // matchId -> teamId

// ---- Resolve ----
function teamsOf(g){return (order[g]||[]).map(id=>BYID[id]);}
function annexKey(){return [...thirds].sort().join('');}
function resolve(s){
  if(!s)return null;
  if(s.t==='w'){const o=order[s.g];return o&&o.length>=1?BYID[o[0]]:null;}
  if(s.t==='ru'){const o=order[s.g];return o&&o.length>=2?BYID[o[1]]:null;}
  if(s.t==='3w'){
     if(thirds.size!==8)return null;
     const v=ANNEX[annexKey()]; if(!v)return null;
     const ag=v[COL[s.wg]]; const o=order[ag];
     return o&&o.length>=3?BYID[o[2]]:null;
  }
  if(s.t==='mw'){const tid=picks[s.m];return tid?BYID[tid]:null;}
  if(s.t==='ml'){const m=MById[s.m];const ta=resolve(m.a),tb=resolve(m.b),tid=picks[s.m];
     if(!ta||!tb||!tid)return null;return tid===ta.id?tb:ta;}
  return null;
}
function validate(){
  let changed=true,pass=0;
  while(changed&&pass++<10){changed=false;
    for(const m of ALLM){const p=picks[m.id];if(p===undefined)continue;
      const ta=resolve(m.a),tb=resolve(m.b);
      if(!ta||!tb||(p!==ta.id&&p!==tb.id)){delete picks[m.id];changed=true;}
    }
  }
}

// ---- Completion ----
const groupsDone=()=>GROUPS.filter(g=>(order[g]||[]).length>=3).length;
const allGroups=()=>groupsDone()===12;
const champion=()=>resolve({t:'mw',m:104});

// ---- Group rendering ----
function rankClass(g,id){const o=order[g]||[];const i=o.indexOf(id);return i===-1?'':'r'+(i+1);}
function ensureFour(g){const o=order[g];if(o&&o.length===3){const last=TEAMS[g].map((_,i)=>g+i).find(id=>!o.includes(id));o.push(last);}}
function clickTeam(g,id){
  let o=order[g]||(order[g]=[]);
  const i=o.indexOf(id);
  if(i===-1){ if(o.length>=4)return; o.push(id); ensureFour(g); }
  else { o.splice(i); } // remove this and all after
  validate(); render();
}
function clearGroup(g){delete order[g];validate();render();}
function renderGroups(){
  const el=document.getElementById('groups');
  el.innerHTML=GROUPS.map(g=>{
    const o=order[g]||[];
    const rows=TEAMS[g].map((t,i)=>{
      const id=g+i;const rc=rankClass(g,id);const pos=o.indexOf(id);
      const tag=pos===0?'WINNER':pos===1?'RUNNER-UP':pos===2?'3RD':pos===3?'OUT':'';
      return `<div class="team ${rc}" data-g="${g}" data-id="${id}">
        <span class="fl">${t[1]}</span><span class="nm">${t[0]}</span>
        <span class="tag">${tag}</span>
        <span class="rk">${pos>=0?pos+1:'·'}</span></div>`;
    }).join('');
    return `<div class="gcard"><div class="gh">
        <span class="gt">Group <span>${g}</span></span>
        <button class="clr" data-clr="${g}">clear</button></div>
        <div class="tlist">${rows}</div>
        <div class="ghint">${o.length>=3?'✓ Ranked':'Tap teams in finishing order'}</div></div>`;
  }).join('');
  el.querySelectorAll('.team').forEach(t=>t.onclick=()=>clickTeam(t.dataset.g,t.dataset.id));
  el.querySelectorAll('.clr').forEach(b=>b.onclick=()=>clearGroup(b.dataset.clr));
  document.getElementById('gprog').innerHTML='Groups ranked: <b>'+groupsDone()+'</b> / 12';
}

// ---- Thirds rendering ----
function toggleThird(g){
  if(thirds.has(g))thirds.delete(g);
  else{if(thirds.size>=8){toast('Deselect one first — exactly 8 advance');return;}thirds.add(g);}
  validate();render();
}
function renderThirds(){
  const body=document.getElementById('thirds-body');
  if(!allGroups()){
    body.innerHTML=`<div class="lock"><h3>Rank your groups first</h3>
      <p>You've ranked ${groupsDone()} of 12 groups. Finish the group stage to reveal the twelve third-placed teams.</p>
      <button class="btn mag" data-go="groups">← Back to groups</button></div>`;
    body.querySelector('[data-go]').onclick=()=>go('groups');return;
  }
  const full=thirds.size>=8;
  const cards=GROUPS.map(g=>{
    const tm=BYID[order[g][2]];const sel=thirds.has(g);
    return `<div class="third ${sel?'sel':''} ${(!sel&&full)?'dis':''}" data-g="${g}">
      <span class="fl">${tm.flag}</span>
      <span class="meta"><div class="nm">${tm.name}</div><div class="gp">3rd · Group ${g}</div></span>
      <span class="chk">✓</span></div>`;
  }).join('');
  body.innerHTML=`<div class="thirds-grid">${cards}</div>
    <div class="thirdsbar">
      <div class="counter"><span>${thirds.size}</span><span class="of"> / 8 selected</span></div>
      <button class="btn mag ${full?'':'ghost'}" id="toko" ${full?'':'disabled style=opacity:.5'}>Seed the bracket →</button>
    </div>`;
  body.querySelectorAll('.third').forEach(c=>c.onclick=()=>toggleThird(c.dataset.g));
  const tk=document.getElementById('toko');if(tk&&full)tk.onclick=()=>go('ko');
  document.getElementById('tprog').innerHTML='Selected: <b>'+thirds.size+'</b> / 8';
}

// ---- Knockout rendering ----
function slotHTML(m,side){
  const s=m[side];const tm=resolve(s);const p=picks[m.id];
  let cls='slot',label,flag='';
  if(tm){flag=tm.flag;label=tm.name;
    if(p===tm.id)cls+=' win';else if(p)cls+=' lose';
  }else{cls+=' empty';flag='○';label=placeholder(s);}
  return `<div class="${cls}" data-m="${m.id}" data-side="${side}">
    <span class="fl">${flag}</span><span class="nm">${label}</span></div>`;
}
function placeholder(s){
  if(s.t==='w')return 'Winner Group '+s.g;
  if(s.t==='ru')return 'Runner-up '+s.g;
  if(s.t==='3w')return 'Best 3rd place';
  if(s.t==='mw')return 'Winner of #'+s.m;
  if(s.t==='ml')return 'Loser of #'+s.m;
  return '';
}
function clickSlot(mid,side){
  const m=MById[mid];const tm=resolve(m[side]);if(!tm)return;
  if(picks[mid]===tm.id)delete picks[mid];else picks[mid]=tm.id;
  validate();render();
}
function renderKO(){
  const body=document.getElementById('ko-body');
  if(thirds.size!==8){
    body.innerHTML=`<div class="lock"><h3>Bracket not seeded yet</h3>
      <p>Rank all 12 groups and select your 8 best third-placed teams, then the Round of 32 seeds itself.</p>
      <button class="btn mag" data-go="thirds">Go to Best Thirds →</button></div>`;
    body.querySelector('[data-go]').onclick=()=>go(allGroups()?'thirds':'groups');
    document.getElementById('champ').className='champ';return;
  }
  document.getElementById('scrollhintHolder');
  let html='<p class="scrollhint">↔ scroll to see all rounds</p><div class="bracket-scroll"><div class="bracket">';
  ROUNDS.forEach(r=>{
    const fin=r.key==='FIN';
    html+=`<div class="round ${fin?'final-col':''}"><div class="rhead">${r.title}<small>${r.date}</small></div><div class="matches">`;
    r.ms.forEach(m=>{
      const isFinal=m.id===104,isThird=m.id===103;
      const tag=isFinal?'★ FINAL':isThird?'3rd-place':('Match '+m.id);
      html+=`<div class="match ${isFinal?'final-m':''} ${isThird?'third-m':''}">
        <div class="mn">${tag}</div>${slotHTML(m,'a')}${slotHTML(m,'b')}</div>`;
    });
    html+='</div></div>';
  });
  html+='</div></div>';
  body.innerHTML=html;
  body.querySelectorAll('.slot:not(.empty)').forEach(s=>s.onclick=()=>clickSlot(+s.dataset.m,s.dataset.side));
  // champion
  const champEl=document.getElementById('champ');const c=champion();
  if(c){champEl.className='champ show';
    champEl.innerHTML=`<div class="champ-in"><span class="tro">🏆</span>
      <div><div class="lbl">Your predicted world champion</div>
      <div class="who"><span>${c.flag}</span>${c.name}</div></div></div>`;
  }else champEl.className='champ';
}

// ---- Tabs ----
function go(s){stage=s;render();
  if(s==='ko')window.scrollTo({top:0,behavior:'smooth'});}
function renderTabs(){
  document.querySelectorAll('.tab').forEach(t=>{
    const k=t.dataset.go;t.classList.toggle('active',
      (k==='groups'&&stage==='groups')||(k==='thirds'&&stage==='thirds')||(k==='ko'&&stage==='ko'));
  });
  document.getElementById('stage-groups').classList.toggle('show',stage==='groups');
  document.getElementById('stage-thirds').classList.toggle('show',stage==='thirds');
  document.getElementById('stage-ko').classList.toggle('show',stage==='ko');
  setDone('groups',allGroups());setDone('thirds',thirds.size===8);setDone('ko',!!champion());
}
function setDone(k,v){document.querySelector('.tab[data-go="'+k+'"]').classList.toggle('done',v);
  document.getElementById('n-'+k).textContent=v?'✓':(k==='groups'?'1':k==='thirds'?'2':'3');}

function render(){renderTabs();
  if(stage==='groups')renderGroups();
  else if(stage==='thirds')renderThirds();
  else renderKO();
}

// ---- Helpers: auto / reset / copy ----
function autoPick(){
  GROUPS.forEach(g=>{
    order[g]=TEAMS[g].map((t,i)=>({id:g+i,r:t[2]})).sort((a,b)=>b.r-a.r).map(x=>x.id);
  });
  // best 8 thirds by rating
  const thirdTeams=GROUPS.map(g=>({g,r:BYID[order[g][2]].rating})).sort((a,b)=>b.r-a.r);
  thirds=new Set(thirdTeams.slice(0,8).map(x=>x.g));
  // knockout by higher rating, in order
  for(const k in picks)delete picks[k];
  for(const m of ALLM){const ta=resolve(m.a),tb=resolve(m.b);
    if(ta&&tb)picks[m.id]=(tb.rating>ta.rating?tb.id:ta.id);}
  render();toast('Filled by ranking — now edit anything you like');
}
function resetAll(){GROUPS.forEach(g=>delete order[g]);thirds=new Set();
  for(const k in picks)delete picks[k];go('groups');toast('Cleared');}
function copySummary(){
  let s='⚽ MY WORLD CUP 2026 BRACKET\n\nGROUP STAGE\n';
  GROUPS.forEach(g=>{const o=order[g]||[];
    s+=`Group ${g}: `+(o.length?o.map((id,i)=>`${i+1}.${BYID[id].name}`).join('  '):'—')+'\n';});
  s+='\nBEST 3RD-PLACE QUALIFIERS\n'+(thirds.size===8?[...thirds].sort().map(g=>BYID[order[g][2]].name).join(', '):'(not chosen)')+'\n';
  const lbl={73:'R32',89:'R16',97:'QF',101:'SF',104:'FINAL',103:'3rd place'};
  s+='\nKNOCKOUT\n';
  [['Round of 32',R32],['Round of 16',R16],['Quarter-finals',QF],['Semi-finals',SF],['3rd place',[THIRDM]],['Final',[FINAL]]].forEach(([t,ms])=>{
    const lines=ms.map(m=>{const ta=resolve(m.a),tb=resolve(m.b),p=picks[m.id];
      if(!ta||!tb)return null;const w=p?BYID[p].name:'?';
      return `  ${ta.name} v ${tb.name} → ${w}`;}).filter(Boolean);
    if(lines.length)s+=`\n${t}\n`+lines.join('\n')+'\n';
  });
  const c=champion();if(c)s+=`\n🏆 CHAMPION: ${c.name}\n`;
  navigator.clipboard?.writeText(s).then(()=>toast('Bracket copied to clipboard'),()=>toast('Copy failed'));
}
let tt;function toast(m){const e=document.getElementById('toast');e.textContent=m;e.classList.add('show');
  clearTimeout(tt);tt=setTimeout(()=>e.classList.remove('show'),2200);}

document.querySelectorAll('.tab').forEach(t=>t.onclick=()=>go(t.dataset.go));
document.getElementById('auto').onclick=autoPick;
document.getElementById('reset').onclick=resetAll;
document.getElementById('copy').onclick=copySummary;

// ---- Theme toggle ----
const themeBtn=document.getElementById('theme');
function applyTheme(t){
  document.documentElement.classList.toggle('light',t==='light');
  themeBtn.textContent=t==='light'?'🌙 Dark':'☀️ Light'; // label = what a click switches to
}
let theme='dark';
try{theme=localStorage.getItem('wc26-theme')||'dark';}catch(e){}
applyTheme(theme);
function setTheme(t){theme=t;applyTheme(t);try{localStorage.setItem('wc26-theme',t);}catch(e){}}
const reduceMotion=matchMedia('(prefers-reduced-motion:reduce)').matches;
themeBtn.onclick=()=>{
  const next=theme==='light'?'dark':'light';
  // Modern path: circular clip-path reveal expanding from the button
  if(document.startViewTransition&&!reduceMotion){
    const r=themeBtn.getBoundingClientRect();
    const x=r.left+r.width/2, y=r.top+r.height/2;
    const end=Math.hypot(Math.max(x,innerWidth-x),Math.max(y,innerHeight-y));
    document.startViewTransition(()=>setTheme(next)).ready.then(()=>{
      document.documentElement.animate(
        {clipPath:[`circle(0px at ${x}px ${y}px)`,`circle(${end}px at ${x}px ${y}px)`]},
        {duration:520,easing:'ease-in-out',pseudoElement:'::view-transition-new(root)'}
      );
    });
    return;
  }
  // Fallback: brief global color cross-fade
  const root=document.documentElement;
  root.classList.add('theme-fade');
  setTheme(next);
  setTimeout(()=>root.classList.remove('theme-fade'),500);
};

render();
